Stream.broadcast runs the source once and relays each emitted chunk to N downstream subscribers via an internal hub. That means you don't pay the cost of pulling twice when you want to compute two summaries in parallel from the same data.

```typescript
import { Effect, Stream, pipe } from "effect";

const src: Stream.Stream<number> = Stream.make(3, 1, 4, 1, 5, 9, 2, 6);

export const minMax: Effect.Effect<readonly [number, number]> = Effect.scoped(
  Effect.gen(function* () {
    const [a, b] = yield* Stream.broadcast(src, 2, 16);
    const lo = yield* pipe(a, Stream.runFold(Number.POSITIVE_INFINITY, Math.min));
    const hi = yield* pipe(b, Stream.runFold(Number.NEGATIVE_INFINITY, Math.max));
    return [lo, hi] as const;
  }),
);
