import { pipe } from "fp-ts/function";

interface Num { readonly _tag: "Num"; readonly value: number }
interface Add { readonly _tag: "Add"; readonly left: Expr; readonly right: Expr }
interface Mul { readonly _tag: "Mul"; readonly left: Expr; readonly right: Expr }
type Expr = Num | Add | Mul;

interface ExprAlgebra<A> {
  readonly Num: (value: number) => A;
  readonly Add: (l: A, r: A) => A;
  readonly Mul: (l: A, r: A) => A;
}

const cata = <A>(algebra: ExprAlgebra<A>) => {
  const go = (e: Expr): A => {
    switch (e._tag) {
      case "Num": return algebra.Num(e.value);
      case "Add": return algebra.Add(go(e.left), go(e.right));
      case "Mul": return algebra.Mul(go(e.left), go(e.right));
    }
  };
  return go;
};

const evalExpr: (e: Expr) => number = cata<number>({
  Num: (v) => v,
  Add: (l, r) => l + r,
  Mul: (l, r) => l * r,
});

const tree: Expr = {
  _tag: "Add",
  left: { _tag: "Num", value: 2 },
  right: { _tag: "Mul", left: { _tag: "Num", value: 3 }, right: { _tag: "Num", value: 4 } },
};

export const sample: number = pipe(tree, evalExpr);
```

