import { pipe } from "fp-ts/function";

interface Nil { readonly _tag: "Nil" }
interface Cons<A> { readonly _tag: "Cons"; readonly head: A; readonly tail: List<A> }
type List<A> = Nil | Cons<A>;

const cata = <A, B>(onNil: () => B, onCons: (head: A, tailResult: B) => B) => {
  const go = (xs: List<A>): B => {
    switch (xs._tag) {
      case "Nil": return onNil();
      case "Cons": return onCons(xs.head, go(xs.tail));
    }
  };
  return go;
};

const length = <A>(xs: List<A>): number =>
  cata<A, number>(() => 0, (_, acc) => acc + 1)(xs);

const sample: List<string> = {
  _tag: "Cons",
  head: "a",
  tail: { _tag: "Cons", head: "b", tail: { _tag: "Nil" } },
};

export const n: number = pipe(sample, length);
```

A catamorphism (generalised fold) separates traversal from interpretation. You supply an algebra — one case per constructor — and the scheme walks the tree, replacing each constructor with its case. Different algebras reuse the same traversal to yield interpreters, pretty-printers or optimisers.

```typescript
import { pipe } from "fp-ts/function";

interface Lit { readonly _tag: "Lit"; readonly value: boolean }
interface And { readonly _tag: "And"; readonly l: BExpr; readonly r: BExpr }
interface Or { readonly _tag: "Or"; readonly l: BExpr; readonly r: BExpr }
interface Not { readonly _tag: "Not"; readonly e: BExpr }
type BExpr = Lit | And | Or | Not;

interface Algebra<A> {
  readonly Lit: (value: boolean) => A;
  readonly And: (l: A, r: A) => A;
  readonly Or: (l: A, r: A) => A;
  readonly Not: (a: A) => A;
}

const cata = <A>(alg: Algebra<A>) => {
  const go = (e: BExpr): A => {
    switch (e._tag) {
      case "Lit": return alg.Lit(e.value);
      case "And": return alg.And(go(e.l), go(e.r));
      case "Or": return alg.Or(go(e.l), go(e.r));
      case "Not": return alg.Not(go(e.e));
    }
  };
  return go;
};

const evalB: (e: BExpr) => boolean = cata<boolean>({
  Lit: (v) => v,
  And: (l, r) => l && r,
  Or: (l, r) => l || r,
  Not: (a) => !a,
});

const sample: BExpr = {
  _tag: "And",
  l: { _tag: "Lit", value: true },
  r: { _tag: "Not", e: { _tag: "Lit", value: false } },
};

export const result: boolean = pipe(sample, evalB);
```

