import { pipe } from "fp-ts/function";

interface Leaf<A> { readonly _tag: "Leaf"; readonly value: A }
interface Branch<A> { readonly _tag: "Branch"; readonly left: Tree<A>; readonly right: Tree<A> }
type Tree<A> = Leaf<A> | Branch<A>;

const cata = <A, B>(onLeaf: (a: A) => B, onBranch: (l: B, r: B) => B) => {
  const go = (t: Tree<A>): B => {
    switch (t._tag) {
      case "Leaf": return onLeaf(t.value);
      case "Branch": return onBranch(go(t.left), go(t.right));
    }
  };
  return go;
};

const sumLeaves: (t: Tree<number>) => number = cata<number, number>(
  (n) => n,
  (l, r) => l + r,
);

const sample: Tree<number> = {
  _tag: "Branch",
  left: { _tag: "Leaf", value: 1 },
  right: {
    _tag: "Branch",
    left: { _tag: "Leaf", value: 2 },
    right: { _tag: "Leaf", value: 3 },
  },
};

export const total: number = pipe(sample, sumLeaves);
```
